import { useEffect, useRef } from "react";
import { useAccount, useConnections, useDisconnect } from "wagmi";
import { disconnectWalletCompletely } from "@/utils/session";
import { walletGetItem } from "@/utils/storage";

interface UseWalletAddressMismatchLogoutOptions {
  /** When false the guard is inactive (e.g. during initial token validation). */
  enabled: boolean;
  /** Called after the session for the old address has been cleared. */
  onMismatch: (storedAddress: string) => void | Promise<void>;
}

/**
 * Watches the currently connected wallet address and compares it with the
 * wallet address stored in the active "wallet" login context. If they differ,
 * it clears the session, disconnects the wallet, and invokes `onMismatch` so
 * the caller can redirect to login.
 */
export function useWalletAddressMismatchLogout({
  enabled,
  onMismatch,
}: UseWalletAddressMismatchLogoutOptions) {
  const { address } = useAccount();
  const connections = useConnections();
  const { mutateAsync: disconnectAsync } = useDisconnect();

  const onMismatchRef = useRef(onMismatch);
  onMismatchRef.current = onMismatch;

  const connectionsRef = useRef(connections);
  connectionsRef.current = connections;

  const disconnectAsyncRef = useRef(disconnectAsync);
  disconnectAsyncRef.current = disconnectAsync;

  const handlingRef = useRef(false);

  useEffect(() => {
    if (!enabled) return;
    if (!address) return;
    if (handlingRef.current) return;

    const raw = walletGetItem("orderlyLoginContext");
    if (!raw) return;

    let context: { method?: string; walletAddress?: string } | null = null;
    try {
      context = JSON.parse(raw) as {
        method?: string;
        walletAddress?: string;
      };
    } catch {
      return;
    }

    if (context?.method !== "wallet" || !context.walletAddress) return;
    if (context.walletAddress.toLowerCase() === address.toLowerCase()) return;

    handlingRef.current = true;
    let cancelled = false;
    const storedAddress = context.walletAddress;

    void (async () => {
      await disconnectWalletCompletely(
        disconnectAsyncRef.current,
        connectionsRef.current,
        storedAddress
      );
      if (!cancelled) {
        await onMismatchRef.current(storedAddress);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [enabled, address]);
}
