import { Outlet, Navigate, useLocation, useParams } from "@remix-run/react";
import { useState, useEffect, useCallback } from "react";
import { defaultLng } from "~/i18n";
import { useWalletAddressMismatchLogout } from "@/hooks/useWalletAddressMismatchLogout";
import { SidebarWrapper } from "~/components/orderly/SidebarWrapper";
import {
  DashboardPageFrame,
  DEFAULT_PAGE_SHELL_CONFIG,
  PageShellProvider,
  type PageShellConfig,
} from "~/components/orderly/PageShell";
import {
  fetchSystemInfo,
  validateDexCreatorAuth,
  type SystemInfo,
} from "~/services/orderly";
import { useTranslation } from "~/i18n";
import { walletGetItem } from "@/utils/storage";
import { clearConnectionStorage } from "@/utils/session";
import { hasCompleteStoredAdminApiKey } from "@/utils/adminKeyAuth";

type ProfileAccessState = {
  role: string | null;
  graduated: boolean;
};

function getProfileAccessState(): ProfileAccessState | null {
  if (typeof window === "undefined") return null;
  const raw = walletGetItem("orderlyProfile");
  if (!raw) return null;
  try {
    const profile = JSON.parse(raw as string) as {
      role?: string;
      brokerId?: string;
      graduated?: boolean;
    };
    return {
      role:
        profile.role ||
        (profile.brokerId === "ambassador" ? "ambassador" : null),
      graduated: Boolean(profile.graduated),
    };
  } catch {
    return null;
  }
}

function getRoutePathname(pathname: string, locale: string) {
  const localePrefix = `/${locale}`;
  if (pathname === localePrefix) return "/";
  if (pathname.startsWith(`${localePrefix}/`)) {
    return pathname.slice(localePrefix.length) || "/";
  }

  const segments = pathname.split("/").filter(Boolean);
  if (segments.length > 0 && /^[a-z]{2}$/i.test(segments[0])) {
    return segments.length === 1 ? "/" : `/${segments.slice(1).join("/")}`;
  }
  return pathname;
}

function isPathAllowedForNonGraduatedBuilder(routePathname: string) {
  const allowedPaths = [
    "/home",
    "/setup",
    "/onboarding",
    "/graduation",
    "/frontend-setup",
    "/deployment-status",
    "/dex-config",
    "/custom-domain",
    "/settings",
    "/settings/api-keys",
  ];

  return allowedPaths.some(
    path => routePathname === path || routePathname.startsWith(`${path}/`)
  );
}

function isPathAllowedForApiLogin(routePathname: string) {
  const allowedPaths = [
    "/affiliate",
    "/points",
    "/permissionless-listing",
    "/order-tags",
    "/distributor-dashboard",
    "/finance",
    "/fee-settings",
    "/data-analytics",
    "/settings",
    "/settings/api-keys",
  ];

  return allowedPaths.some(
    path => routePathname === path || routePathname.startsWith(`${path}/`)
  );
}

function readLoginContext(): {
  method?: string;
  walletAddress?: string;
} | null {
  const raw = walletGetItem("orderlyLoginContext");
  if (!raw) return null;
  try {
    return JSON.parse(raw) as { method?: string; walletAddress?: string };
  } catch {
    return null;
  }
}

function isLoggedIn() {
  if (typeof window === "undefined") return false;
  return !!walletGetItem("orderlyLoginContext");
}

function formatCountdown(ms: number) {
  if (ms <= 0) return "ending soon";
  const totalSeconds = Math.floor(ms / 1000);
  const days = Math.floor(totalSeconds / 86400);
  const hours = Math.floor((totalSeconds % 86400) / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;
  if (days > 0) return `${days}d ${hours}h ${minutes}m`;
  if (hours > 0) return `${hours}h ${minutes}m ${seconds}s`;
  return `${minutes}m ${seconds}s`;
}

function MaintenanceMode({ systemInfo }: { systemInfo: SystemInfo }) {
  const { t } = useTranslation();
  const [now, setNow] = useState(Date.now());
  const endTime = systemInfo.scheduled_maintenance?.endTime;

  useEffect(() => {
    const id = window.setInterval(() => setNow(Date.now()), 1000);
    return () => window.clearInterval(id);
  }, []);

  return (
    <div className="flex min-h-screen items-center justify-center bg-(--bg-base) px-4 text-center">
      <div className="max-w-lg rounded-2xl border border-[rgba(217,171,82,0.35)] bg-[rgba(217,171,82,0.08)] p-8 shadow-xl">
        <div className="mx-auto mb-5 flex h-14 w-14 items-center justify-center rounded-full bg-[rgba(217,171,82,0.18)] text-[#D9AB52]">
          <span className="text-2xl">!</span>
        </div>
        <h1 className="mb-3 text-2xl font-semibold text-(--fg-primary)">
          {t("app.maintenance.title")}
        </h1>
        <p className="mb-5 text-sm leading-6 text-(--fg-secondary)">
          {systemInfo.msg || t("app.maintenance.description")}
        </p>
        {endTime && (
          <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-4">
            <div className="mb-1 text-xs uppercase tracking-wide text-(--fg-secondary)">
              {t("app.maintenance.estimatedEndTime")}
            </div>
            <div className="text-sm font-medium text-(--fg-primary)">
              {new Date(endTime).toLocaleString()}
            </div>
            <div className="mt-3 text-lg font-semibold text-[#D9AB52]">
              {formatCountdown(endTime - now)}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default function DashboardLayout() {
  const { lang } = useParams<{ lang: string }>();
  const locale = lang || defaultLng;
  const location = useLocation();
  const routePathname = getRoutePathname(location.pathname, locale);
  const [profileAccess, setProfileAccess] = useState<ProfileAccessState | null>(
    () => getProfileAccessState()
  );
  const [systemInfo, setSystemInfo] = useState<SystemInfo | null>(null);
  const [systemInfoChecked, setSystemInfoChecked] = useState(false);
  const [tokenValidated, setTokenValidated] = useState(false);
  const [pageShellConfig, setPageShellConfig] = useState<PageShellConfig>(
    DEFAULT_PAGE_SHELL_CONFIG
  );

  const redirectToLogin = useCallback(
    (reason?: string) => {
      clearConnectionStorage();
      const redirectTo = `${location.pathname}${location.search}`;
      const loginUrl = `/${locale}/login?redirect=${encodeURIComponent(redirectTo)}`;
      if (reason) {
        window.location.href = `${loginUrl}&reason=${encodeURIComponent(reason)}`;
      } else {
        window.location.href = loginUrl;
      }
    },
    [locale, location.pathname, location.search]
  );

  useEffect(() => {
    let cancelled = false;

    async function validateToken() {
      const token = walletGetItem("auth_token");
      const context = readLoginContext();
      const walletAddress = context?.walletAddress;

      if (context?.method === "api") {
        if (hasCompleteStoredAdminApiKey({ skipWalletCheck: true })) {
          if (!cancelled) setTokenValidated(true);
        } else if (!cancelled) {
          redirectToLogin("session_expired");
        }
        return;
      }

      if (!token || !walletAddress) {
        if (!cancelled) redirectToLogin("session_expired");
        return;
      }

      try {
        const valid = await validateDexCreatorAuth(walletAddress, token);
        if (cancelled) return;
        if (!valid) {
          redirectToLogin("session_expired");
          return;
        }
        setTokenValidated(true);
      } catch {
        if (!cancelled) setTokenValidated(true);
      }
    }

    validateToken();
    return () => {
      cancelled = true;
    };
  }, [redirectToLogin]);

  useEffect(() => {
    function handleTokenExpired() {
      redirectToLogin("session_expired");
    }
    window.addEventListener("authTokenExpired", handleTokenExpired);
    return () => {
      window.removeEventListener("authTokenExpired", handleTokenExpired);
    };
  }, [redirectToLogin]);

  useWalletAddressMismatchLogout({
    enabled: tokenValidated && isLoggedIn(),
    onMismatch: () => redirectToLogin("wallet_changed"),
  });

  useEffect(() => {
    function refreshAuthState() {
      setProfileAccess(getProfileAccessState());
    }
    window.addEventListener("profileUpdated", refreshAuthState);
    window.addEventListener("authChanged", refreshAuthState);
    window.addEventListener("storage", refreshAuthState);
    return () => {
      window.removeEventListener("profileUpdated", refreshAuthState);
      window.removeEventListener("authChanged", refreshAuthState);
      window.removeEventListener("storage", refreshAuthState);
    };
  }, []);

  useEffect(() => {
    let cancelled = false;
    fetchSystemInfo()
      .then(info => {
        if (!cancelled) setSystemInfo(info);
      })
      .catch(() => {
        if (!cancelled) setSystemInfo(null);
      })
      .finally(() => {
        if (!cancelled) setSystemInfoChecked(true);
      });
    return () => {
      cancelled = true;
    };
  }, []);

  if (systemInfoChecked && systemInfo?.status === 2) {
    return <MaintenanceMode systemInfo={systemInfo} />;
  }

  if (!tokenValidated) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-(--bg-base)">
        <span className="inline-block h-8 w-8 animate-spin rounded-full border-2 border-(--line-subtle) border-t-(--fg-brand)" />
      </div>
    );
  }

  const hasLoginContext = isLoggedIn();
  if (!hasLoginContext) {
    const redirectTo = `${location.pathname}${location.search}`;
    return (
      <Navigate
        to={`/${locale}/login?redirect=${encodeURIComponent(redirectTo)}`}
        replace
      />
    );
  }

  const loginContext = readLoginContext();
  const isApiLogin = loginContext?.method === "api";

  const isAmbassadorDistributor = profileAccess?.role === "ambassador";
  const ambassadorAllowedPaths = [
    `/${locale}/distributor-dashboard`,
    `/${locale}/onboarding`,
    `/${locale}/settings`,
    `/${locale}/settings/api-keys`,
  ];
  if (
    isAmbassadorDistributor &&
    !ambassadorAllowedPaths.includes(location.pathname)
  ) {
    return (
      <Navigate
        to={`/${locale}/distributor-dashboard${location.search}`}
        replace
      />
    );
  }

  if (isApiLogin && !isPathAllowedForApiLogin(routePathname)) {
    return (
      <Navigate
        to={`/${locale}/${isAmbassadorDistributor ? "distributor-dashboard" : "affiliate"}${location.search}`}
        replace
      />
    );
  }

  const isNonGraduatedBuilder =
    profileAccess && !isAmbassadorDistributor && !profileAccess.graduated;
  if (
    isNonGraduatedBuilder &&
    !isPathAllowedForNonGraduatedBuilder(routePathname)
  ) {
    return <Navigate to={`/${locale}/home${location.search}`} replace />;
  }

  const useDashboardFrame = location.pathname !== `/${locale}/onboarding`;
  const framePageShellConfig: PageShellConfig =
    routePathname === "/frontend-setup"
      ? { pageTitle: "Frontend setup" }
      : pageShellConfig;

  return (
    <PageShellProvider value={{ setPageShellConfig }}>
      <SidebarWrapper />
      {useDashboardFrame ? (
        <DashboardPageFrame
          pageTitle={framePageShellConfig.pageTitle}
          parentTitle={framePageShellConfig.parentTitle}
        >
          <Outlet />
        </DashboardPageFrame>
      ) : (
        <Outlet />
      )}
    </PageShellProvider>
  );
}
