import { useLocation } from "@remix-run/react";
import { useCallback, useEffect, useState } from "react";
import { Sidebar, setSidebarMobileOpen } from "./Sidebar";

export function SidebarWrapper() {
  const location = useLocation();
  const hideSidebar =
    location.pathname === "/login" ||
    location.pathname === "/" ||
    location.pathname.endsWith("/onboarding");
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    setMobileOpen(false);
    setSidebarMobileOpen(false);
  }, [location.pathname]);

  useEffect(() => {
    function handleMobileToggle(e: Event) {
      const custom = e as CustomEvent<{ open: boolean }>;
      setMobileOpen(custom.detail.open);
    }
    window.addEventListener("sidebarMobileToggle", handleMobileToggle);
    return () =>
      window.removeEventListener("sidebarMobileToggle", handleMobileToggle);
  }, []);

  const handleMobileOpenChange = useCallback((open: boolean) => {
    setMobileOpen(open);
    setSidebarMobileOpen(open);
    window.dispatchEvent(
      new CustomEvent("sidebarMobileToggle", { detail: { open } })
    );
  }, []);

  if (hideSidebar) return null;
  return (
    <Sidebar
      mobileOpen={mobileOpen}
      onMobileOpenChange={handleMobileOpenChange}
    />
  );
}
